CustomField.formula:
IF(
    OR(
        ISBLANK(CompletedDateTime),
        Owner:Queue.QueueName <> "Sales Admin"
    ),
    "",

    /* Total seconds */
    IF(
        (CompletedDateTime - CreatedDate) * 86400 <= 0,
        "",

        /* Days */
        IF(
            FLOOR((CompletedDateTime - CreatedDate) * 86400 / 86400) > 0,
            TEXT(FLOOR((CompletedDateTime - CreatedDate) * 86400 / 86400)) &
            IF(
                FLOOR((CompletedDateTime - CreatedDate) * 86400 / 86400) = 1,
                " Day ",
                " Days "
            ),
            ""
        ) &

        /* Hours */
        IF(
            FLOOR(
                MOD((CompletedDateTime - CreatedDate) * 86400, 86400) / 3600
            ) > 0,
            TEXT(
                FLOOR(
                    MOD((CompletedDateTime - CreatedDate) * 86400, 86400) / 3600
                )
            ) &
            IF(
                FLOOR(
                    MOD((CompletedDateTime - CreatedDate) * 86400, 86400) / 3600
                ) = 1,
                " Hour ",
                " Hours "
            ),
            ""
        ) &

        /* Minutes */
        IF(
            FLOOR(
                MOD((CompletedDateTime - CreatedDate) * 86400, 3600) / 60
            ) > 0,
            TEXT(
                FLOOR(
                    MOD((CompletedDateTime - CreatedDate) * 86400, 3600) / 60
                )
            ) &
            IF(
                FLOOR(
                    MOD((CompletedDateTime - CreatedDate) * 86400, 3600) / 60
                ) = 1,
                " Minute ",
                " Minutes "
            ),
            ""
        ) &

        /* Seconds */
        IF(
            FLOOR(MOD((CompletedDateTime - CreatedDate) * 86400, 60)) > 0,
            TEXT(FLOOR(MOD((CompletedDateTime - CreatedDate) * 86400, 60))) &
            IF(
                FLOOR(MOD((CompletedDateTime - CreatedDate) * 86400, 60)) = 1,
                " Second",
                " Seconds"
            ),
            ""
        )
    )
)
